1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_PERCENT = 10;
3	
4	const BASE_PREMIUM: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	};
8	
9	interface Item {
10	  type: string;
11	}
12	
13	interface Step {
14	  op: string;
15	  items?: Item[];
16	}
17	
18	interface Scenario {
19	  customer: { yearsWithMHPCO: number };
20	  steps: Step[];
21	}
22	
23	const quotePremium = (items: Item[]): number => {
24	  if (items.length === 0) return PROCESSING_FEE;
25	  const base = items.reduce((sum, it) => sum + BASE_PREMIUM[it.type], 0);
26	  const withFirstInsuranceTimes100 = base * 100 + base * FIRST_INSURANCE_PERCENT;
27	  return Math.ceil(withFirstInsuranceTimes100 / 100) + PROCESSING_FEE;
28	};
29	
30	export const runScenario = (input: unknown): { results: unknown[] } => {
31	  const scenario = input as Scenario;
32	  const results = scenario.steps.map((step) => ({
33	    premium: quotePremium(step.items ?? []),
34	  }));
35	  return { results };
36	};
37

